it("should keep live cell with three neighbors (survival)", () => {
  // Grid: 3x3, center cell (1,1) is alive with 3 neighbors
  const grid: Grid = [
    [false, true, false],
    [true, true, false],
    [false, false, false],
  ];
  const result = nextGeneration(grid);
  // Center cell should stay alive (3 neighbors = survival)
  expect(result).toEqual([
    [false, true, false],
    [true, true, false],
    [false, false, false],
  ]);
});
